const webhook = $('Webhook').first();
const bitacoraRow = $('Get a row').first();
const logoItem = $('Obtener Logo1').first();
const body = webhook.json.body ?? webhook.json;

if (!webhook.binary?.data) {
  throw new Error('Falta el archivo binario data en el webhook (campo multipart data)');
}

if (!body.idBitacora) {
  throw new Error('Falta idBitacora en el webhook');
}

if (!bitacoraRow?.json?.id) {
  throw new Error('No se encontro la bitacora en Supabase con id: ' + body.idBitacora);
}

const bitacora = bitacoraRow.json;
const logoBin = logoItem.binary?.logo ?? logoItem.binary?.data;
if (!logoBin) {
  throw new Error('No se pudo obtener el logo');
}

return [{
  json: {
    body,
    ...bitacora,
    formulario: bitacora.formulario ?? {},
  },
  binary: {
    data: webhook.binary.data,
    logo: logoBin,
  },
}];

const sharp = require('sharp');

const items = $input.all();

for (let i = 0; i < items.length; i++) {
  try {
    const item = items[i];

    if (!item.binary?.data) {
      throw new Error(`No existe binario data. Disponibles: ${Object.keys(item.binary ?? {}).join(', ')}`);
    }
    if (!item.binary?.logo) {
      throw new Error(`No existe binario logo. Disponibles: ${Object.keys(item.binary ?? {}).join(', ')}`);
    }

    const fotoBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const logoBuffer = await this.helpers.getBinaryDataBuffer(i, 'logo');

    const body = item.json.body || {};
    const formulario = item.json.formulario || {};

    const custodio =
      formulario.responsableOrigen?.nombre ||
      formulario.operador1?.nombre ||
      'Custodio';
    const fecha = body.fecha || '';
    const hora = body.hora || '';
    const lat = body.latitud ?? '';
    const lon = body.longitud ?? '';
    const estatus = body.estatus || '';

    const svgWidth = 450;
    const svgHeight = 170;

    const svgText = `
      <svg width="${svgWidth}" height="${svgHeight}">
        <style>
          .text { fill: #ffffff; font-size: 20px; font-family: sans-serif; font-weight: bold; text-anchor: end; }
          .estatus { fill: #ffcc00; font-size: 28px; font-family: sans-serif; font-weight: bold; text-anchor: end; }
        </style>
        <rect x="0" y="0" width="${svgWidth}" height="${svgHeight}" fill="rgba(0,0,0,0.6)" rx="8" />
        <text x="${svgWidth - 20}" y="45" class="estatus">ESTATUS: ${String(estatus).toUpperCase()}</text>
        <text x="${svgWidth - 20}" y="85" class="text">Custodio: ${custodio}</text>
        <text x="${svgWidth - 20}" y="115" class="text">Fecha: ${fecha} - Hora: ${hora}</text>
        <text x="${svgWidth - 20}" y="145" class="text">Ubicacion: ${lat}, ${lon}</text>
      </svg>
    `;

    const textBuffer = Buffer.from(svgText);
    const resizedLogo = await sharp(logoBuffer).resize({ width: 150, withoutEnlargement: true }).toBuffer();

    const outputBuffer = await sharp(fotoBuffer)
      .resize({ width: 1024, withoutEnlargement: true })
      .composite([
        { input: resizedLogo, gravity: 'northwest' },
        { input: textBuffer, gravity: 'southeast' },
      ])
      .jpeg({ quality: 80 })
      .toBuffer();

    const base64Image = outputBuffer.toString('base64');

    items[i].json = {
      ...item.json,
      imageBase64: base64Image,
      imageDataUri: `data:image/jpeg;base64,${base64Image}`,
      mimeType: 'image/jpeg',
      fileName: `reporte_${body.idBitacora ?? 'ruta'}_${Date.now()}.jpg`,
    };

    delete items[i].binary;
  } catch (error) {
    throw new Error(`Error procesando imagen: ${error.message}`);
  }
}

return items;

const proc = $('Procesar Imagen1').first().json;
const bitacora = $('Get a row').first().json;
const body = $('Webhook').first().json.body ?? $('Webhook').first().json;
const idBitacora = body.idBitacora;
const custodioId = bitacora.custodio_id;

if (!custodioId) {
  throw new Error('La bitacora no tiene custodio_id');
}

const storagePath = `${custodioId}/${idBitacora}/${proc.fileName}`;
const buffer = Buffer.from(proc.imageBase64, 'base64');

return [{
  json: {
    ...proc,
    storagePath,
    idBitacora,
    custodioId,
  },
  binary: {
    file: await this.helpers.prepareBinaryData(buffer, proc.fileName, 'image/jpeg'),
  },
}];

const prep = $('Preparar upload Storage').first().json;
const signResp = $input.first().json;
const BASE_URL = 'https://torolfqiwrrhqocguwjg.supabase.co';

let url_imagen = signResp.signedUrl || signResp.signedURL || '';

if (url_imagen.startsWith('/')) {
  url_imagen = `${BASE_URL}/storage/v1${url_imagen}`;
} else if (url_imagen && !url_imagen.startsWith('http')) {
  url_imagen = `${BASE_URL}/storage/v1/${url_imagen.replace(/^\//, '')}`;
}

if (!url_imagen) {
  throw new Error('Supabase no devolvio signedURL para la evidencia');
}

return [{
  json: {
    ...prep,
    storagePath: prep.storagePath,
    url_imagen,
  },
}];

const bitacora = $('Get a row').first().json;
const webhookBody = $('Webhook').first().json.body || $('Webhook').first().json;
const imagen = $('Procesar Imagen1').first().json;
const evidencia = $('Resolver URL evidencia').first().json;

const form = bitacora.formulario || {};
const respOrigen = form.responsableOrigen || {};
const op1 = form.operador1 || {};
const veh = op1.vehiculo || {};
const dest = form.destino || {};

let contactos = bitacora.contactos;
if (typeof contactos === 'string') {
  try { contactos = JSON.parse(contactos); } catch { contactos = []; }
}
if (!Array.isArray(contactos)) contactos = [];

const ruta = bitacora.ruta || '';
const destinoTxt = dest.municipio || (ruta.includes('→') ? ruta.split('→')[1].trim() : '—');

// Evolution API: media = URL https o base64 puro (NO data URI)
const mediaWhatsapp = imagen.imageBase64 || evidencia.url_imagen || '';

return [{
  json: {
    estado: webhookBody.estatus || '',
    hora: webhookBody.hora || '',
    coordenadas: `${webhookBody.latitud || ''}, ${webhookBody.longitud || ''}`,
    cliente: bitacora.empresa_contratante || '',
    custodio: respOrigen.nombre || op1.nombre || 'Custodio',
    destino: destinoTxt,
    origen: webhookBody.direccion || '',
    modelo: veh.modelo || '—',
    color_unidad: veh.color || '—',
    placas_unidad: bitacora.unidad || veh.placas || '—',
    nombre_servicio: bitacora.nombre || '',
    contactos,
    imagen: mediaWhatsapp,
    url_imagen: evidencia.url_imagen || '',
    imageBase64: imagen.imageBase64 || '',
    idBitacora: webhookBody.idBitacora || '',
    custodio_id: bitacora.custodio_id || '',
    storagePath: evidencia.storagePath || '',
  },
}];

const raw = $input.first().json;
const row = Array.isArray(raw) ? raw[0] : raw;
if (!row?.id) {
  throw new Error('No se pudo activar la bitacora en Supabase (PATCH sin filas)');
}
return [{
  json: {
    ...row,
    bitacora_estado: row.estado || 'activo',
  },
}];

const datos = $('Preparar campos WhatsApp').first().json;
const activacion = $('Normalizar activacion').first()?.json ?? {};
let contactos = datos.contactos;
if (typeof contactos === 'string') {
  try { contactos = JSON.parse(contactos); } catch { contactos = []; }
}
if (!Array.isArray(contactos) || contactos.length === 0) {
  return [];
}
const { contactos: _, ...datosDelServicio } = datos;
return contactos.map((contacto) => ({
  json: {
    ...contacto,
    ...datosDelServicio,
    captionKind: 'inicio',
    bitacora_estado: activacion.bitacora_estado || activacion.estado || 'activo',
    start_time: activacion.start_time || '',
  },
}));

